        this.playnow.name = "playnow";
        this.playnow.parent = this;
        this.playnow.setTransform(828.4, 496.5, 1, 1, 0, 0, 0, 60.5, 60.5);
        this.playnow.cache(-16, -10, 143, 130);

        this.timeline.addTween(cjs.Tween.get(this.playnow).wait(1));

        // waiter
